/**
 * Email notification adapter — delivers notifications via email.
 *
 * Provides template rendering per notification type, recipient validation,
 * and in-memory delivery (suitable for testing; swap the transport for production).
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** A rendered email ready for delivery. */
export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

/** Template rendering output. */
export interface RenderedTemplate {
  subject: string;
  html: string;
  text: string;
}

/** Options for configuring the email adapter. */
export interface EmailAdapterOptions {
  /** Sender address shown in the From field. */
  fromAddress?: string;
  /** Application name used in templates. */
  appName?: string;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Render an email template for the given notification type.
 * Each notification type has its own subject line and body layout.
 */
export function renderTemplate(payload: NotificationPayload): RenderedTemplate {
  switch (payload.type) {
    case 'order_confirmation':
      return renderOrderConfirmation(payload);
    case 'order_status_update':
      return renderOrderStatusUpdate(payload);
    case 'user_welcome':
      return renderUserWelcome(payload);
    case 'user_updated':
      return renderUserUpdated(payload);
    default: {
      const _exhaustive: never = payload.type;
      return renderFallback(payload);
    }
  }
}

function renderOrderConfirmation(payload: NotificationPayload): RenderedTemplate {
  const orderId = payload.metadata?.orderId as string | undefined;
  const text = payload.body;
  const html = [
    '<div style="font-family: sans-serif;">',
    `<h1>Order Confirmation</h1>`,
    orderId ? `<p><strong>Order:</strong> ${escapeHtml(orderId)}</p>` : '',
    `<p>${escapeHtml(text)}</p>`,
    '<p>Thank you for your purchase!</p>',
    '</div>',
  ].join('\n');

  return { subject: payload.subject, html, text };
}

function renderOrderStatusUpdate(payload: NotificationPayload): RenderedTemplate {
  const previousStatus = payload.metadata?.previousStatus as string | undefined;
  const newStatus = payload.metadata?.newStatus as string | undefined;
  const text = payload.body;
  const html = [
    '<div style="font-family: sans-serif;">',
    '<h1>Order Status Update</h1>',
    previousStatus && newStatus
      ? `<p>Status changed: <strong>${escapeHtml(previousStatus)}</strong> &rarr; <strong>${escapeHtml(newStatus)}</strong></p>`
      : '',
    `<p>${escapeHtml(text)}</p>`,
    '</div>',
  ].join('\n');

  return { subject: payload.subject, html, text };
}

function renderUserWelcome(payload: NotificationPayload): RenderedTemplate {
  const text = payload.body;
  const html = [
    '<div style="font-family: sans-serif;">',
    '<h1>Welcome to TaskFlow Pro!</h1>',
    `<p>${escapeHtml(text)}</p>`,
    '<p>Get started by creating your first order.</p>',
    '</div>',
  ].join('\n');

  return { subject: payload.subject, html, text };
}

function renderUserUpdated(payload: NotificationPayload): RenderedTemplate {
  const changes = payload.metadata?.changes as string[] | undefined;
  const text = payload.body;
  const html = [
    '<div style="font-family: sans-serif;">',
    '<h1>Account Updated</h1>',
    `<p>${escapeHtml(text)}</p>`,
    changes && changes.length > 0
      ? `<p>Fields changed: ${changes.map(escapeHtml).join(', ')}</p>`
      : '',
    '</div>',
  ].join('\n');

  return { subject: payload.subject, html, text };
}

function renderFallback(payload: NotificationPayload): RenderedTemplate {
  const html = [
    '<div style="font-family: sans-serif;">',
    `<h1>${escapeHtml(payload.subject)}</h1>`,
    `<p>${escapeHtml(payload.body)}</p>`,
    '</div>',
  ].join('\n');

  return { subject: payload.subject, html, text: payload.body };
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Validate that a recipient string is a plausible email address.
 */
export function validateRecipient(recipient: string): { valid: boolean; error?: string } {
  if (!recipient || recipient.trim().length === 0) {
    return { valid: false, error: 'Recipient email address is empty' };
  }
  if (!EMAIL_REGEX.test(recipient)) {
    return { valid: false, error: `Invalid email address: ${recipient}` };
  }
  return { valid: true };
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];
  private fromAddress: string;
  private appName: string;

  constructor(options?: EmailAdapterOptions) {
    this.fromAddress = options?.fromAddress ?? 'noreply@taskflowpro.com';
    this.appName = options?.appName ?? 'TaskFlow Pro';
  }

  /**
   * Send a notification as an email.
   * Validates the recipient, renders the template, and stores the email.
   * In production, replace the storage step with an SMTP transport call.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate recipient
      const validation = validateRecipient(payload.recipient);
      if (!validation.valid) {
        this.logger.error(`Recipient validation failed: ${validation.error}`);
        return {
          success: false,
          channel: this.channel,
          notificationId: payload.id,
          error: validation.error!,
          deliveredAt: new Date(),
        };
      }

      // Render template
      const rendered = renderTemplate(payload);

      // Build email message
      const email: EmailMessage = {
        to: payload.recipient,
        subject: rendered.subject,
        htmlBody: rendered.html,
        textBody: rendered.text,
        sentAt: new Date(),
      };

      // Deliver (in-memory for now; production would call SMTP transport here)
      this.sentEmails.push(email);
      this.logger.info(`Email delivered to ${payload.recipient}: ${rendered.subject}`);

      return {
        success: true,
        channel: this.channel,
        notificationId: payload.id,
        deliveredAt: email.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        notificationId: payload.id,
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /** Get all sent emails. Useful for testing. */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails. Useful for testing. */
  clearSentEmails(): void {
    this.sentEmails = [];
  }

  /** Get the configured from address. */
  getFromAddress(): string {
    return this.fromAddress;
  }

  /** Get the configured app name. */
  getAppName(): string {
    return this.appName;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailNotificationAdapter,
  renderTemplate,
  validateRecipient,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('validateRecipient', () => {
  it('should accept a valid email', () => {
    expect(validateRecipient('alice@example.com')).toEqual({ valid: true });
  });

  it('should reject an empty string', () => {
    const result = validateRecipient('');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('empty');
  });

  it('should reject a string without @', () => {
    const result = validateRecipient('not-an-email');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid');
  });

  it('should reject a string with spaces', () => {
    const result = validateRecipient('alice @example.com');
    expect(result.valid).toBe(false);
  });
});

describe('renderTemplate', () => {
  it('should render order_confirmation with order ID', () => {
    const payload = makePayload();
    const result = renderTemplate(payload);

    expect(result.subject).toBe('Order Confirmation: order-1');
    expect(result.html).toContain('Order Confirmation');
    expect(result.html).toContain('order-1');
    expect(result.html).toContain('Thank you for your purchase');
    expect(result.text).toBe(payload.body);
  });

  it('should render order_status_update with status transition', () => {
    const payload = makePayload({
      type: 'order_status_update',
      subject: 'Order Update: order-1',
      body: 'Your order status has changed from pending to confirmed.',
      metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
    });
    const result = renderTemplate(payload);

    expect(result.html).toContain('Order Status Update');
    expect(result.html).toContain('pending');
    expect(result.html).toContain('confirmed');
    expect(result.text).toContain('pending');
  });

  it('should render user_welcome', () => {
    const payload = makePayload({
      type: 'user_welcome',
      subject: 'Welcome to TaskFlow Pro!',
      body: 'Hi Alice, welcome to TaskFlow Pro. Your account has been created.',
      metadata: { userId: 'user-1' },
    });
    const result = renderTemplate(payload);

    expect(result.html).toContain('Welcome to TaskFlow Pro');
    expect(result.html).toContain('Get started');
    expect(result.text).toContain('Alice');
  });

  it('should render user_updated with changes list', () => {
    const payload = makePayload({
      type: 'user_updated',
      subject: 'Account Updated',
      body: 'Your account has been updated.',
      metadata: { userId: 'user-1', changes: ['name', 'email'] },
    });
    const result = renderTemplate(payload);

    expect(result.html).toContain('Account Updated');
    expect(result.html).toContain('name');
    expect(result.html).toContain('email');
  });

  it('should escape HTML entities in content', () => {
    const payload = makePayload({
      body: 'Items: <script>alert("xss")</script>',
    });
    const result = renderTemplate(payload);

    expect(result.html).not.toContain('<script>');
    expect(result.html).toContain('&lt;script&gt;');
  });
});

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    adapter = new EmailNotificationAdapter();
  });

  it('should have channel "email"', () => {
    expect(adapter.channel).toBe('email');
  });

  it('should use default config values', () => {
    expect(adapter.getFromAddress()).toBe('noreply@taskflowpro.com');
    expect(adapter.getAppName()).toBe('TaskFlow Pro');
  });

  it('should accept custom options', () => {
    const custom = new EmailNotificationAdapter({
      fromAddress: 'support@myapp.com',
      appName: 'My App',
    });
    expect(custom.getFromAddress()).toBe('support@myapp.com');
    expect(custom.getAppName()).toBe('My App');
  });

  describe('send', () => {
    it('should deliver a valid notification and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store the rendered email', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const emails = adapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]!.to).toBe('alice@example.com');
      expect(emails[0]!.subject).toBe('Order Confirmation: order-1');
      expect(emails[0]!.htmlBody).toContain('<h1>');
      expect(emails[0]!.textBody).toBe(payload.body);
      expect(emails[0]!.sentAt).toBeInstanceOf(Date);
    });

    it('should fail for invalid recipient', async () => {
      const payload = makePayload({ recipient: 'not-an-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email');
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should fail for empty recipient', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });

    it('should handle multiple sends', async () => {
      await adapter.send(makePayload({ id: 'n1', recipient: 'a@b.com' }));
      await adapter.send(makePayload({ id: 'n2', recipient: 'c@d.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return defensive copy from getSentEmails', async () => {
      await adapter.send(makePayload());
      const emails1 = adapter.getSentEmails();
      const emails2 = adapter.getSentEmails();

      expect(emails1).not.toBe(emails2);
      expect(emails1).toEqual(emails2);
    });
  });
});

